INSERT INTO sections(id, chapter_id, title, content_type, content, duration_minutes, sort_order) VALUES(
  'ed546b9c-52d0-83f2-5dfa-a1a53374e593'::uuid,
  '959ed075-17fc-5ba4-48c9-6691315f8b53'::uuid,
  '1.1 文本预处理',
  'markdown',
  '[{"type":"markdown","content":"\n# 1.1 文本预处理\n\n## 学习目标\n\n通过本节学习，你将能够：\n- 理解文本预处理的重要性\n- 掌握文本清洗、分词、去除停用词等技术\n- 使用NLTK、spaCy等工具进行文本预处理\n- 了解中文分词的特殊性\n\n---\n\n## 1.1.1 为什么需要文本预处理？\n\n**问题**：\n- 原始文本包含噪声（标点符号、特殊字符、停用词等）\n- 计算机无法直接理解文本\n- 需要将文本转换为数值形式\n\n**解决方案**：文本预处理\n- 清洗文本\n- 分词（Tokenization）\n- 去除停用词\n- 词形还原（Lemmatization）/词干提取（Stemming）\n- 转换为数值表示\n\n## 1.1.2 文本预处理的步骤\n\n### 1. 文本清洗（Text Cleaning）\n\n**任务**：\n- 去除HTML标签\n- 去除标点符号\n- 去除特殊字符\n- 转换为小写\n\n**代码示例**（使用正则表达式）：\n\n\\`\\`\\`python\nimport re\n\ndef clean_text(text):\n    # 去除HTML标签\n    text = re.sub(r''<[^>]+>'', '''', text)\n    # 去除标点符号和特殊字符\n    text = re.sub(r''[^a-zA-Z0-9\\s]'', '''', text)\n    # 转换为小写\n    text = text.lower()\n    return text\n\ntext = \"<p>Hello, World! This is a test.</p>\"\ncleaned_text = clean_text(text)\nprint(cleaned_text)  # hello world this is a test\n\\`\\`\\`\n\n### 2. 分词（Tokenization）\n\n**任务**：将文本分割成单词或子词\n\n**英文分词**（使用NLTK）：\n\n\\`\\`\\`python\nimport nltk\nfrom nltk.tokenize import word_tokenize\n\ntext = \"Hello, world! This is a test.\"\ntokens = word_tokenize(text)\nprint(tokens)  # [''Hello'', '','', ''world'', ''!'', ''This'', ''is'', ''a'', ''test'', ''.'']\n\\`\\`\\`\n\n**中文分词**（使用jieba）：\n\n\\`\\`\\`python\nimport jieba\n\ntext = \"我爱自然语言处理\"\ntokens = jieba.lcut(text)\nprint(tokens)  # [''我'', ''爱'', ''自然语言处理'']\n\\`\\`\\`\n\n### 3. 去除停用词（Stop Words Removal）\n\n**停用词**：在文本中频繁出现但对语义贡献不大的词（如：the, is, at, which）\n\n**代码示例**（使用NLTK）：\n\n\\`\\`\\`python\nfrom nltk.corpus import stopwords\nimport nltk\n\nnltk.download(''stopwords'')\nstop_words = set(stopwords.words(''english''))\n\ntext = \"This is a simple example of stop words removal.\"\ntokens = word_tokenize(text)\nfiltered_tokens = [word for word in tokens if word.lower() not in stop_words]\nprint(filtered_tokens)  # [''simple'', ''example'', ''stop'', ''words'', ''removal'', ''.'']\n\\`\\`\\`\n\n### 4. 词形还原和词干提取\n\n**词形还原（Lemmatization）**：将单词还原为原型（如：running → run, better → good）\n\n**词干提取（Stemming）**：将单词还原为词根（如：running → run, better → bett）\n\n**代码示例**：\n\n\\`\\`\\`python\nfrom nltk.stem import WordNetLemmatizer, PorterStemmer\n\n# 词形还原\nlemmatizer = WordNetLemmatizer()\nprint(lemmatizer.lemmatize(''running'', pos=''v''))  # run\nprint(lemmatizer.lemmatize(''better'', pos=''a''))   # good\n\n# 词干提取\nstemmer = PorterStemmer()\nprint(stemmer.stem(''running''))  # run\nprint(stemmer.stem(''better''))   # better（词干提取可能不准确）\n\\`\\`\\`\n\n## 1.1.3 使用spaCy进行文本预处理\n\n**spaCy**是一个强大的NLP库，集成了多种预处理功能。\n\n**代码示例**：\n\n\\`\\`\\`python\nimport spacy\n\n# 加载英文模型\nnlp = spacy.load(''en_core_web_sm'')\n\ntext = \"Apple is looking at buying U.K. startup for $1 billion.\"\ndoc = nlp(text)\n\n# 分词\ntokens = [token.text for token in doc]\nprint(tokens)\n\n# 去除停用词和标点符号\nfiltered_tokens = [token.text for token in doc if not token.is_stop and not token.is_punct]\nprint(filtered_tokens)\n\n# 词形还原\nlemmas = [token.lemma_ for token in doc]\nprint(lemmas)\n\\`\\`\\`\n\n## 1.1.4 中文文本预处理\n\n**挑战**：\n- 中文没有空格分隔单词\n- 需要专门的分词工具\n\n**工具**：\n- **jieba**：最常用的中文分词工具\n- **pkuseg**：北京大学开发的分词工具\n- **THULAC**：清华大学开发的分词工具\n\n**代码示例**（使用jieba）：\n\n\\`\\`\\`python\nimport jieba\nimport re\n\ndef clean_chinese_text(text):\n    # 去除标点符号和特殊字符\n    text = re.sub(r''[^\\u4e00-\\u9fa5\\s]'', '''', text)\n    return text\n\ndef tokenize_chinese_text(text):\n    # 分词\n    tokens = jieba.lcut(text)\n    # 去除停用词（需要自己准备中文停用词表）\n    stop_words = set([''的'', ''了'', ''在'', ''是'', ''我'', ''有'', ''和'', ''就'', ''不'', ''人'', ''都'', ''一'', ''一个'', ''上'', ''也'', ''很'', ''到'', ''说'', ''要'', ''去'', ''你'', ''会'', ''着'', ''没有'', ''看'', ''好'', ''自己'', ''这''])\n    filtered_tokens = [token for token in tokens if token not in stop_words]\n    return filtered_tokens\n\ntext = \"我爱自然语言处理！这是一个很好的工具。\"\ncleaned_text = clean_chinese_text(text)\ntokens = tokenize_chinese_text(cleaned_text)\nprint(tokens)  # [''我'', ''爱'', ''自然语言处理'', ''这是'', ''一个'', ''很'', ''好'', ''工具'']\n\\`\\`\\`\n\n---\n\n## 实战练习\n\n### 练习1：英文文本预处理\n\n**任务**：\n1. 使用NLTK对一段英文文本进行预处理\n2. 包括：文本清洗、分词、去除停用词、词形还原\n\n### 练习2：中文文本预处理\n\n**任务**：\n1. 使用jieba对一段中文文本进行预处理\n2. 包括：文本清洗、分词、去除停用词\n\n---\n\n## 本章小结\n\n在本节中，我们学习了：\n1. **文本预处理的重要性**：清洗噪声，转换为数值形式\n2. **文本预处理的步骤**：清洗、分词、去除停用词、词形还原\n3. **工具**：NLTK、spaCy、jieba\n4. **中英文预处理的差异**\n\n**关键要点**：\n- 文本预处理是NLP的基础\n- 英文有空格分隔，中文需要分词\n- 选择合适的工具可以提高效率\n\n**下一节预告**：我们将学习词嵌入（Word Embedding）。\n\n---\n\n**恭喜你完成了第1章第1节！** 🎉\n        "}]'::jsonb,
  30,
  1
);
INSERT INTO sections(id, chapter_id, title, content_type, content, duration_minutes, sort_order) VALUES(
  '0c266521-a66f-61c1-d63f-46f6bdd260b7'::uuid,
  '959ed075-17fc-5ba4-48c9-6691315f8b53'::uuid,
  '1.2 词嵌入（Word Embedding）',
  'markdown',
  '[{"type":"markdown","content":"\n# 1.2 词嵌入（Word Embedding）\n\n## 学习目标\n\n通过本节学习，你将能够：\n- 理解词嵌入的原理\n- 掌握Word2Vec、GloVe、FastText等算法\n- 使用预训练的词嵌入模型\n- 了解词嵌入的应用场景\n\n---\n\n## 1.2.1 什么是词嵌入？\n\n**问题**：\n- 计算机无法直接理解单词\n- 需要将单词转换为数值形式\n\n**解决方案**：词嵌入（Word Embedding）\n- 将单词映射到连续的向量空间\n- 语义相似的单词在向量空间中距离较近\n\n**示例**：\n- king - man + woman ≈ queen\n- 词嵌入可以捕捉语义关系\n\n## 1.2.2 常用的词嵌入算法\n\n### 1. Word2Vec\n\n**原理**：\n- 使用神经网络学习词嵌入\n- 两种模型：\n  - **CBOW**（Continuous Bag of Words）：根据上下文预测中心词\n  - **Skip-gram**：根据中心词预测上下文\n\n**代码示例**（使用Gensim）：\n\n\\`\\`\\`python\nfrom gensim.models import Word2Vec\n\n# 准备语料\nsentences = [\n    [''this'', ''is'', ''a'', ''sentence''],\n    [''this'', ''is'', ''another'', ''sentence'']\n]\n\n# 训练Word2Vec模型\nmodel = Word2Vec(sentences, vector_size=100, window=5, min_count=1, workers=4)\n\n# 获取词向量\nvector = model.wv[''sentence'']\nprint(vector.shape)  # (100,)\n\n# 找相似词\nsimilar_words = model.wv.most_similar(''sentence'', topn=5)\nprint(similar_words)\n\\`\\`\\`\n\n### 2. GloVe\n\n**原理**：\n- 基于全局词频统计\n- 训练目标：词的共现概率比\n\n**使用预训练的GloVe词嵌入**：\n\n\\`\\`\\`python\nimport numpy as np\n\n# 加载预训练的GloVe词嵌入\ndef load_glove_embeddings(glove_file):\n    embeddings = {}\n    with open(glove_file, ''r'', encoding=''utf-8'') as f:\n        for line in f:\n            values = line.split()\n            word = values[0]\n            vector = np.asarray(values[1:], dtype=''float32'')\n            embeddings[word] = vector\n    return embeddings\n\nembeddings = load_glove_embeddings(''glove.6B.100d.txt'')\nvector = embeddings[''sentence'']\nprint(vector.shape)  # (100,)\n\\`\\`\\`\n\n### 3. FastText\n\n**原理**：\n- 基于子词（subword）的嵌入\n- 可以处理未登录词（out-of-vocabulary words）\n\n**代码示例**（使用Gensim）：\n\n\\`\\`\\`python\nfrom gensim.models import FastText\n\n# 准备语料\nsentences = [\n    [''this'', ''is'', ''a'', ''sentence''],\n    [''this'', ''is'', ''another'', ''sentence'']\n]\n\n# 训练FastText模型\nmodel = FastText(sentences, vector_size=100, window=5, min_count=1, workers=4)\n\n# 获取词向量\nvector = model.wv[''sentence'']\nprint(vector.shape)  # (100,)\n\n# FastText可以处理未登录词\nvector = model.wv[''sentencer'']  # 未登录词\nprint(vector.shape)  # (100,)\n\\`\\`\\`\n\n## 1.2.3 使用预训练的词嵌入模型\n\n**常用的预训练词嵌入模型**：\n- **Word2Vec**：Google提供的预训练模型\n- **GloVe**：Stanford提供的预训练模型\n- **FastText**：Facebook提供的预训练模型\n\n**在PyTorch中使用预训练词嵌入**：\n\n\\`\\`\\`python\nimport torch\nimport torch.nn as nn\n\n# 假设我们已经有了词嵌入矩阵（从预训练模型加载）\nembedding_matrix = torch.randn(10000, 100)  # 10000个词，每个词100维\n\n# 创建嵌入层\nembedding_layer = nn.Embedding.from_pretrained(embedding_matrix, freeze=False)\n\n# 使用嵌入层\ninput_ids = torch.LongTensor([[1, 2, 3], [4, 5, 6]])  # 词的ID\nembeddings = embedding_layer(input_ids)\nprint(embeddings.shape)  # torch.Size([2, 3, 100])\n\\`\\`\\`\n\n## 1.2.4 词嵌入的应用场景\n\n**应用**：\n1. **文本分类**：将文本转换为词嵌入，然后输入分类器\n2. **情感分析**：使用词嵌入捕捉情感信息\n3. **机器翻译**：将源语言和目标语言的词映射到同一空间\n4. **推荐系统**：使用词嵌入表示用户和物品\n\n---\n\n## 实战练习\n\n### 练习1：训练Word2Vec模型\n\n**任务**：\n1. 使用Gensim训练一个Word2Vec模型\n2. 在自定义数据集上训练\n3. 测试词向量的质量（找相似词）\n\n### 练习2：使用预训练的GloVe词嵌入\n\n**任务**：\n1. 加载预训练的GloVe词嵌入\n2. 在文本分类任务上使用\n3. 对比使用和不使用预训练词嵌入的性能\n\n---\n\n## 本章小结\n\n在本节中，我们学习了：\n1. **词嵌入的原理**：将单词映射到向量空间\n2. **常用算法**：Word2Vec、GloVe、FastText\n3. **使用预训练模型**：加载和使用预训练词嵌入\n4. **应用场景**：文本分类、情感分析等\n\n**关键要点**：\n- 词嵌入可以捕捉语义关系\n- 预训练词嵌入可以提升模型性能\n- FastText可以处理未登录词\n\n**下一节预告**：我们将学习循环神经网络（RNN）。\n\n---\n\n**恭喜你完成了第1章第2节！** 🎉\n        "}]'::jsonb,
  30,
  2
);

INSERT INTO chapters(id, course_id, title, sort_order) VALUES(
  'b3a60eb7-962e-0c87-81b0-cf4a824b918e'::uuid,
  'b483bb8a-9710-aab2-493b-de0b2a829311'::uuid,
  '第2章：循环神经网络与注意力机制',
